module top_module(
   input clk,
   input rst,
   input enable,
   output reg [3:0] out
);reg [3:0] cnt;
reg [3:0] next_count;

always @ (posedge clk) begin
   if (rst) begin
      cnt <= 4'b0;
   end else begin
      cnt <= next_count;
   end
end

always @ (*) begin
   if (enable) begin
      next_count = cnt + 4'b1;
   end else begin
      next_count = cnt;
   end
end

assign out = cnt;

endmodule
